CREATE TABLE `barreaux_france` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `barreau` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `region` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ville_siege` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cour_appel` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tribunal_judiciaire` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cour_appel_metropolitaine` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nombre_avocats` int DEFAULT NULL,
  `actif` tinyint(1) NOT NULL DEFAULT '1',
  PRIMARY KEY (`id`),
  KEY `idx_barreau_nom` (`barreau`),
  KEY `idx_barreau_region` (`region`),
  KEY `idx_barreau_ville` (`ville_siege`),
  KEY `idx_barreau_actif` (`actif`)
) ENGINE=InnoDB AUTO_INCREMENT=165 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
